class Player {
  final String? id;
  final String? userId;
  final String? teamId;
  final String? name;
  final String? note;
  final DateTime? createdAt; // assumes UTC
  final bool? deleteFlag;
  final DateTime? updatedAt; // assumes UTC
  final String? imageUrl;
  final String? presignedImageUrl;
  final Handedness pitchingHand;
  final Handedness hittingHand;
  final DateTime? birthday;

  const Player({
    this.id,
    this.userId,
    this.teamId,
    this.name,
    this.note,
    this.createdAt,
    this.deleteFlag,
    this.updatedAt,
    this.imageUrl,
    this.presignedImageUrl,
    this.pitchingHand = Handedness.none,
    this.hittingHand = Handedness.none,
    this.birthday,
  });

  factory Player.fromJson(Map<String, dynamic> json) {
    return Player(
      id: json['id'] as String?,
      userId: json['userId'] as String?,
      teamId: json['teamId'] as String?,
      name: json['name'] as String?,
      note: json['note'] as String?,
      createdAt: json['createdAt'] == null
          ? null
          : DateTime.parse(json['createdAt'] as String),

