void _expectList<T, U>(
    List<T> actual, List<U> expected, Function(T, U) comparator) {
  expect(
    actual.length,
    expected.length,
    reason:
        'list length does not match: (actual: ${actual.length}, expected: ${expected.length})',
  );
  for (var i = 0; i < actual.length; i++) {
    comparator(actual[i], expected[i]);
  }
}

void _expectSession(Session actual, Session expected) {
  expect(actual.id, expected.id);
  expect(actual.title, expected.title);
  expect(actual.teamId, expected.teamId);
  expect(actual.userId, expected.userId);
  expect(actual.playerId, expected.playerId);
  expect(actual.location, expected.location);
  expect(actual.note, expected.note);
  expect(actual.deleteFlag, expected.deleteFlag);

  final playerExpected =
      playerRecords.data.firstWhere((player) => player.id == actual.playerId);
  _expectPlayer(actual.player!, playerExpected);
}

void _expectPlayer(Player actual, Player expected) {
  expect(actual.id, expected.id);
  expect(actual.userId, expected.userId);
  expect(actual.teamId, expected.teamId);
  expect(actual.name, expected.name);
  expect(actual.note, expected.note);
  expect(actual.deleteFlag, actual.deleteFlag);
}

void _expectResource(ResourceData actual, ResourceData expected) {
  expect(actual.id, expected.id);
  expect(actual.focalLength, expected.focalLength);
  expect(actual.longsideAngleOfView, expected.longsideAngleOfView);
  expect(actual.fps, expected.fps);
  expect(actual.uploadFilename, expected.uploadFilename);
  expect(actual.originalVideoFilename, expected.originalVideoFilename);
  expect(actual.movieWidth, expected.movieWidth);
  expect(actual.movieHeight, expected.movieHeight);

