   377→void expectRightAsync<T>(AsyncValue<Result<Failure, T>> actual) {
   378→  expect(actual.hasValue, true);
   379→  expectRight(actual.value!);
   380→}
   381→
   382→/// Wait until AsyncValue.loading of the value of provider is false.
   383→Future<AsyncValue<T>> waitForAsyncValue<T>(
   384→  ProviderContainer ref,
   385→  ProviderListenable<AsyncValue<T>> provider,
   386→) {
   387→  final completer = Completer<AsyncValue<T>>();
   388→
   389→  ProviderSubscription<AsyncValue<T>>? subscription;
   390→  subscription = ref.listen(
   391→    provider,
   392→    (prev, next) {
   393→      if (next.isLoading) {
   394→        return;
   395→      }
   396→      // in case of fireImmediately
   397→      Future.microtask(() {
   398→        subscription!.close();
   399→        completer.complete(next);
   400→      });
   401→    },
   402→    fireImmediately: true,
   403→  );
   404→
   405→  return completer.future;
   406→}
