    test('completeSignUp', () async {
      final response = await ref
          .read(loginStateControllerProvider.notifier)
          .completeSignUp(token);
      expectRight(response);
    });
  });
}

void expectRightAsync<T>(AsyncValue<Result<Failure, T>> actual) {
  expect(actual.hasValue, true);
  expectRight(actual.value!);
}

/// Wait until AsyncValue.loading of the value of provider is false.
Future<AsyncValue<T>> waitForAsyncValue<T>(
  ProviderContainer ref,
  ProviderListenable<AsyncValue<T>> provider,
) {
  final completer = Completer<AsyncValue<T>>();

  ProviderSubscription<AsyncValue<T>>? subscription;
  subscription = ref.listen(
    provider,
    (prev, next) {
      if (next.isLoading) {
        return;
      }
      // in case of fireImmediately
      Future.microtask(() {
        subscription!.close();
        completer.complete(next);
      });
    },
    fireImmediately: true,
  );

  return completer.future;
}

