List<BallInfo> _createExpectedBallInfoList(
  ResourceData resource,
) {
  // This mimics api server logic
  final balls = Map.fromEntries(ballRecords.data
      .where((ball) =>
          ball.resourceId == resource.id &&
          ((ball.isPitched ?? false) || (ball.isHit ?? false)))
      .sortedBy<num>((ball) => ball.id!)
      .map((ball) => MapEntry(ball.ballIndex!, ball)));
  final ballPositions = ballPositionRecords.data
      .where((ballPosition) => ballPosition.resourceId == resource.id)
      .sortedBy<num>((ballPosition) => ballPosition.id!)
      .groupListsBy((ballPosition) => ballPosition.ballIndex!);
  final ballInfoListExpected = balls.entries
      .map(
        (ballEntry) => BallInfo(
          ball: ballEntry.value,
          positions: ballPositions[ballEntry.key] ?? [],
        ),
      )
      .toList();

  return ballInfoListExpected;
}

void _expectList<T, U>(
    List<T> actual, List<U> expected, Function(T, U) comparator) {
  expect(
    actual.length,
    expected.length,
    reason:
        'list length does not match: (actual: ${actual.length}, expected: ${expected.length})',
  );
  for (var i = 0; i < actual.length; i++) {
    comparator(actual[i], expected[i]);
  }
}

