void _expectMap<K, V1, V2>(
    Map<K, V1> actual, Map<K, V2> expected, void Function(V1, V2) validator) {
  expect(actual.keys.length, expected.keys.length);
  for (final expectedEntry in expected.entries) {
    expect(actual.containsKey(expectedEntry.key), true);
    final actualValue = actual[expectedEntry.key];
    if (actualValue != null) {
