  // Check team relationship
  print('teamMultipleUsers.id: ${teamMultipleUsers.id}');
  print('userTeamAdmin.teamId: ${userTeamAdmin.teamId}');
  print('Match: ${teamMultipleUsers.id == userTeamAdmin.teamId}');

  print('\n=== Expected Sessions for teamMultipleUsers ===');

  // Filter sessions by teamId (simulating the expectSessions logic)
  final expectedSessions = sessionRecords.data
      .where((session) =>
          !session.deleteFlag! &&
          session.teamId == teamMultipleUsers.id)
      .toList();

  print('Expected sessions count: ${expectedSessions.length}');
  for (final session in expectedSessions) {
    print('Session: id=${session.id}, teamId=${session.teamId}, playerId=${session.playerId}, title=${session.title}');
  }

  print('\n=== All Sessions in Test Data ===');
  for (final session in sessionRecords.data) {
    print('Session: id=${session.id}, teamId=${session.teamId}, playerId=${session.playerId}, title=${session.title}, deleteFlag=${session.deleteFlag}');
  }

  print('\n=== All Users and Their Team IDs ===');
  print('userTeamAdmin: id=${userTeamAdmin.id}, teamId=${userTeamAdmin.teamId}');
  print('userTeamMember: id=${userTeamMember.id}, teamId=${userTeamMember.teamId}');
  print('userWriteTest: id=${userWriteTest.id}, teamId=${userWriteTest.teamId}');
}

