import 'dart:ui';

// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:package_info_plus/package_info_plus.dart';
import 'package:shared_preferences/shared_preferences.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/clients/auth/auth_client.dart';
import 'package:baseball_detector_flutter/data/clients/background_http_client.dart';
import 'package:baseball_detector_flutter/data/profile_storage.dart';
import 'package:baseball_detector_flutter/data/repositories/api_server_repository.dart';
import 'package:baseball_detector_flutter/modules/amplify/amplify.dart';
import 'package:baseball_detector_flutter/providers/auth_client_provider.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller_fake.dart';
import 'mock_amplify_secure_storage.dart';
import 'mock_flutter_secure_storage.dart';
import 'mock_path_plugin.dart';
import 'mock_shared_preferences.dart';

Future<ProviderContainer> createContainer() async {
  await mockPathPlugin();

  // mock SharedPreferencesStore and create ProfileStorage
  mockSharedPreferences();
  mockFlutterSecureStorage();
  mockAmplifySecureStorageMessageChannels();

  await BackgroundHttpClient.initialize();

  final sharedPreferences = await SharedPreferences.getInstance();
  final profileStorage = ProfileStorageImpl(sharedPreferences);

  // setup Amplify SDK
  await configureAmplifySdk(forTesting: true);
  final authClient = AuthClientImpl(
    profileStorage,
    const Locale('en'),
    '1.1.0+58',
  );
  final repository = APIServerRepository(
    profileStorage: profileStorage,
    locale: const Locale('en'),
    appVersion: '1.1.0+58',
  );

  // setup Riverpod and mock providers
  return ProviderContainer(
    overrides: [
      profileStorageProvider.overrideWithValue(profileStorage),
      authClientProvider.overrideWithValue(authClient),
      repositoryProvider.overrideWithValue(repository),
      userAccessibleContentsControllerProvider
          .overrideWith(() => FakeUserAccessibleContentsController()),
    ],
  );
}

Future<PackageInfo> mockGetPackageInfo() async {
  return PackageInfo(
    appName: 'TestApp',
    packageName: 'test.app',
    version: '1.0.0',
    buildNumber: '1',
    buildSignature: '',
  );
}

