      page: page,
      pageSize: pageSize,
      userId: isTeamCrossing ? null : userId,
      playerId: playerId,
      location: location,
      dateFrom: startDate?.toUtc(),
      dateTo: endDate?.toUtc(),
      orderBy: SessionSearchRequestOrderBy.createdAt,
      isOrderDesc: true,
    ).toJson(),
    responseMapper: SessionSearchResponse.fromJson,
  );
  if (response.hasLeft) {
    return Left(response.left);
